ngx_http_js_access_handler(ngx_http_request_t *r)
{
    ngx_int_t                rc;
    ngx_http_js_ctx_t       *ctx;
    ngx_http_js_loc_conf_t  *jlcf;

    jlcf = ngx_http_get_module_loc_conf(r, ngx_http_js_module);

    if (jlcf->access.len == 0) {
        return NGX_DECLINED;
    }

    if (r != r->main) {
        return NGX_DECLINED;
    }

    rc = ngx_http_js_init_vm(r, ngx_http_js_request_proto_id);
    if (rc != NGX_OK) {
        return rc;
    }

    ctx = ngx_http_get_module_ctx(r, ngx_http_js_module);

    if (ctx->in_progress) {
        if (ngx_js_ctx_pending(ctx)) {
            return NGX_AGAIN;
        }

        ctx->in_progress = 0;

        if (ctx->rejected_promises != NULL
            && ctx->rejected_promises->items > 0)
        {
            return NGX_HTTP_INTERNAL_SERVER_ERROR;
        }

        return ngx_http_js_access_finalize(r, ctx);
    }

    ctx->status = NGX_OK;

    ngx_log_debug1(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
                   "http js access handler \"%V\"", &jlcf->access);

    rc = ctx->engine->call((ngx_js_ctx_t *) ctx, &jlcf->access, &ctx->args[0],
                           1);

    if (rc == NGX_ERROR) {
        return NGX_HTTP_INTERNAL_SERVER_ERROR;
    }

    /* JS called readRequest*(). */

    if (ngx_http_js_body_read_is_deferred(ctx->body_read_state)) {

        rc = ngx_http_read_client_request_body(r, ngx_http_js_access_body_done);

        if (rc >= NGX_HTTP_SPECIAL_RESPONSE) {
            ngx_http_js_body_read_abort(ctx);
            return rc;
        }

        r->preserve_body = 1;

        if (rc == NGX_OK) {
            /*
             * Sync: access_body_done callback already fired, resolved
             * or rejected the promise.  access_body_finalize() returned
             * without running posted requests.  Fall through to let
             * the pending/status check handle the result.
             */
            ctx->body_read_state = NGX_HTTP_JS_BODY_READ_IDLE;
            goto done;
        }

        ctx->body_read_state = ngx_http_js_body_read_to_in_progress(
                                                         ctx->body_read_state);
        ctx->in_progress = 1;
        ngx_http_finalize_request(r, NGX_DONE);
        return NGX_DONE;
    }

done:

    if (ngx_js_ctx_pending(ctx)) {
        ctx->in_progress = 1;
        r->write_event_handler = ngx_http_js_access_write_event_handler;
        return NGX_AGAIN;
    }

    return ngx_http_js_access_finalize(r, ctx);
}


static ngx_int_t
ngx_http_js_access_finalize(ngx_http_request_t *r, ngx_http_js_ctx_t *ctx)
{
    ngx_int_t  rc;

    if (ctx->redirect_uri.len) {
        rc = ngx_http_js_internal_redirect(r, ctx);
        ngx_http_finalize_request(r, rc);
        return NGX_DONE;
    }

    if (r->header_sent) {
        ngx_http_finalize_request(r, NGX_OK);
        return NGX_DONE;
    }

    return ctx->status;
}


static void
ngx_http_js_access_write_event_handler(ngx_http_request_t *r)
{
    ngx_int_t          rc;
    ngx_http_js_ctx_t  *ctx;

    ctx = ngx_http_get_module_ctx(r, ngx_http_js_module);

    ngx_log_debug0(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
                   "http js access write event handler");

    if (ngx_js_ctx_pending(ctx)) {
        return;
    }

    rc = ngx_http_js_access_finalize(r, ctx);

    if (rc == NGX_DONE) {
        return;
    }

    ngx_http_core_run_phases(r);
}


static ngx_int_t
ngx_http_js_content_handler(ngx_http_request_t *r)
{
    ngx_int_t  rc;

    ngx_log_debug0(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
                   "http js content handler");

    rc = ngx_http_read_client_request_body(r,
                                           ngx_http_js_content_event_handler);

    if (rc >= NGX_HTTP_SPECIAL_RESPONSE) {
        return rc;
    }

    return NGX_DONE;
}


static void
ngx_http_js_content_event_handler(ngx_http_request_t *r)
{
    ngx_int_t                rc;
    ngx_http_js_ctx_t       *ctx;
    ngx_http_js_loc_conf_t  *jlcf;

    ngx_log_debug0(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
                   "http js content event handler");

    rc = ngx_http_js_init_vm(r, ngx_http_js_request_proto_id);

    if (rc == NGX_ERROR || rc == NGX_DECLINED) {
        ngx_http_finalize_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
        return;
    }

    jlcf = ngx_http_get_module_loc_conf(r, ngx_http_js_module);

    ngx_log_debug1(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
                   "http js content call \"%V\"" , &jlcf->content);

    ctx = ngx_http_get_module_ctx(r, ngx_http_js_module);

    /*
     * status is expected to be overriden by finish(), return() or
     * internalRedirect() methods, otherwise the content handler is
     * considered invalid.
     */

    ctx->status = NGX_HTTP_INTERNAL_SERVER_ERROR;

    rc = ctx->engine->call((ngx_js_ctx_t *) ctx, &jlcf->content, &ctx->args[0],
                           1);

    if (rc == NGX_ERROR) {
        ngx_http_finalize_request(r, NGX_HTTP_INTERNAL_SERVER_ERROR);
        return;
    }

    if (rc == NGX_AGAIN) {
        r->write_event_handler = ngx_http_js_content_write_event_handler;
        return;
    }

    ngx_http_js_content_finalize(r, ctx);
}


static void
ngx_http_js_content_write_event_handler(ngx_http_request_t *r)
{
    ngx_event_t               *wev;
    ngx_connection_t          *c;
    ngx_http_js_ctx_t         *ctx;
    ngx_http_core_loc_conf_t  *clcf;

    ngx_log_debug0(NGX_LOG_DEBUG_HTTP, r->connection->log, 0,
                   "http js content write event handler");

    c = r->connection;
    ctx = ngx_http_get_module_ctx(r, ngx_http_js_module);

    if (!ngx_js_ctx_pending(ctx)) {
        ngx_http_js_content_finalize(r, ctx);

        if (!c->buffered) {
            return;
        }
    }

    wev = c->write;

